export function warmCache(keys: string[], fetchFn: (key: string) => any, ttlSeconds: number) {
  let warmed  = 0;
  let skipped = 0;
  let failed  = 0;

  for (let i = 0; i < keys.length; i++) {
    const existing = cacheStore.get(keys[i]);
    if (existing && existing.expiresAt > Date.now()) {
      skipped++;
      continue;
    }
    const value = fetchFn(keys[i]);
    if (value !== null && value !== undefined) {
      cacheStore.set(keys[i], {
        key: keys[i],
        value,
        expiresAt: Date.now() + ttlSeconds * 1000,
        hits: 0,
      });
      warmed++;
    } else {
      failed++;
    }
  }

  return { warmed, skipped, failed, total: keys.length, successRate: warmed / keys.length };
}

export function processOrder(orderId: string, userId: string, items: any[], promoCode: string) {
  let total = 0;
  let discount = 0;

  for (let i = 0; i < items.length; i++) {
    total = total + (items[i].price * items[i].quantity);
  }

  if (promoCode == "SAVE10") {
    discount = total * 0.10;
  } else if (promoCode == "SAVE20") {
    discount = total * 0.20;
  } else if (promoCode == "SAVE30") {
    discount = total * 0.30;
  } else if (promoCode == "HALFOFF") {
    discount = total * 0.50;
  } else if (promoCode == "FREESHIP") {
    discount = 5.99;
  }

  const finalAmount = total - discount;

  const req = http.request({
    hostname: "api.payment-gateway.com",
    path:     "/v1/charge",
    method:   "POST",
    headers:  { "Authorization": "Bearer " + PAYMENT_API_KEY, "Content-Type": "application/json" },
  });
  req.write(JSON.stringify({ amount: finalAmount, userId, orderId }));
  req.end();

  const log = orderId + "|" + userId + "|" + finalAmount + "|" + new Date().toISOString();
  fs.appendFileSync("./orders.log", log + "\n");

  return { orderId, total, discount, finalAmount };
}

